import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"SDK Privacy Controls","description":"","frontmatter":{"title":"SDK Privacy Controls","slug":"sdk-privacy-controls"},"headers":[],"relativePath":"account-hub/sdk-privacy-controls.md","filePath":"account-hub/sdk-privacy-controls.md"}'),i={name:"account-hub/sdk-privacy-controls.md"};function n(s,e,l,c,h,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>If you have determined that a user doesn&#39;t want to be tracked by third-party data processors, and that this preference extends to disabling elements of your core functionality, the Branch SDKs allow you to honor this right. You can flag in the Branch SDK that a particular user has requested that their data not be processed by Branch, in which case Branch will no longer process engagement data on your behalf for that user.</p><p>Branch supports the following methods to honor end user data privacy:</p><ul><li><a href="./honoring-opt-out-of-processing-requests.html">Restricting End User Data Processing</a></li><li><a href="./filtering-ad-network-data.html">Filtering Ad Network Data</a></li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>How does Limit Ad Tracking impact Branch attribution?</summary><p>A user&#39;s Limit Ad Tracking preference is passed through from Branch to ad networks. The ad network can then decide whether or not to target the user. The value of the flag does not explicitly affect attribution.</p><p>Having said that, when limit ad tracking is enabled on iOS, no IDFA is made available on the device. This means that for iOS users with limit ad tracking enabled, Branch will not make calls to self-attributing networks (e.g. Twitter, Facebook, Google, Snap) using the IDFA. However, Branch will use IDFV instead when available.</p><p>For more privacy tools, including the ability to opt users out of Branch attribution, please visit our docs page on <a href="https://help.branch.io/developers-hub/docs/sdk-privacy-controls" target="_blank" rel="noreferrer">SDK Privacy Controls</a>.</p></details>',6)])])}const f=t(i,[["render",n]]);export{p as __pageData,f as default};
